#include "controller.h"

static void controller_force_safe_state(controller_t *controller)
{
    if (controller == NULL) {
        return;
    }

    controller->compressor_on = false;
    controller->vent_open = true;
    controller->state = CONTROLLER_STATE_SAFE_VENT;
}

static bool controller_sensor_stale(bool has_valid_sample, uint32_t sample_ms, uint32_t now_ms)
{
    if (!has_valid_sample) {
        return false;
    }

    return (uint32_t) (now_ms - sample_ms) > CONTROLLER_SENSOR_TIMEOUT_MS;
}

static void controller_apply_state(controller_t *controller, controller_state_t state)
{
    if (controller == NULL) {
        return;
    }

    switch (state) {
    case CONTROLLER_STATE_PRESSURIZING:
        controller->compressor_on = true;
        controller->vent_open = false;
        controller->state = CONTROLLER_STATE_PRESSURIZING;
        break;

    case CONTROLLER_STATE_RELIEVING:
        controller->compressor_on = false;
        controller->vent_open = true;
        controller->state = CONTROLLER_STATE_RELIEVING;
        break;

    case CONTROLLER_STATE_HOLDING:
        controller->state = CONTROLLER_STATE_HOLDING;
        if (controller->compressor_on && controller->vent_open) {
            controller_force_safe_state(controller);
        }
        break;

    case CONTROLLER_STATE_SAFE_VENT:
